      "content": "import { siteConfig } from "@/site.config";

export function githubRepoUrl(): string {
  const { owner, repo } = siteConfig.githubRepo;
  return `https://github.com/${owner}/${repo}`;
}

/** Compact display for star counts (e.g. 1.2k, 10k). */
export function formatStarCount(n: number): string {
  if (n < 1000) return String(n);
  const k = n / 1000;
  const s = k >= 10 ? k.toFixed(0) : k.toFixed(1);
  return `${s.replace(/\.0$/, "")}k`;
}

/**
 * Public repo stargazers from GitHub API. Cached 1h; returns null on failure.
 */
export async function getGithubStargazerCount(): Promise<number | null> {
  const { owner, repo } = siteConfig.githubRepo;
  try {
    const res = await fetch(`https://api.github.com/repos/${owner}/${repo}`, {
      next: { revalidate: 3600 },
      headers: {
        Accept: "application/vnd.github+json",
        "User-Agent": `${siteConfig.site_name}-Site`,
      },
    });
    if (!res.ok) return null;
    const data = (await res.json()) as { stargazers_count?: unknown };
    const n = data.stargazers_count;
    return typeof n === "number" && Number.isFinite(n) ? n : null;
  } catch {
    return null;
  }
}
