      "content": "import { getWordPressUrl } from "@/lib/env";

/** httpOnly cookie — matches lib/woo-graph.ts for one session token across account (and any GraphQL use). */
export { WOO_JWT_COOKIE } from "@/lib/woo-graph";

const JWT_MAX_AGE_SEC = 60 * 60 * 24 * 14;

export function getJwtCookieOptions(maxAgeSec: number = JWT_MAX_AGE_SEC) {
  return {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax" as const,
    path: "/",
    maxAge: maxAgeSec,
  };
}

/** JWT Authentication for WP REST API — default namespace `jwt-auth/v1`. */
export function getJwtTokenEndpoint(): string | null {
  const base = getWordPressUrl();
  if (!base) return null;
  const ns =
    process.env.WORDPRESS_JWT_NAMESPACE?.trim().replace(/^\/|\/$/g, "") ||
    "jwt-auth/v1";
  return `${base}/wp-json/${ns}/token`;
}

export async function requestWordPressJwt(
  username: string,
  password: string
): Promise<
  { ok: true; token: string } | { ok: false; message: string; status: number }
> {
  const url = getJwtTokenEndpoint();
  if (!url) {
    return { ok: false, message: "WORDPRESS_URL is not configured.", status: 503 };
  }
  try {
    const res = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json", Accept: "application/json" },
      body: JSON.stringify({ username, password }),
      cache: "no-store",
    });
    let data: Record<string, unknown> = {};
    try {
      data = (await res.json()) as Record<string, unknown>;
    } catch {
      /* empty */
    }
    if (!res.ok) {
      const m = data.message;
      const msg =
        typeof m === "string"
          ? m
          : Array.isArray(m)
            ? m.map(String).join(" ")
            : res.statusText || "Login failed";
      return { ok: false, message: msg, status: res.status };
    }
    const token = typeof data.token === "string" ? data.token : "";
    if (!token) {
      return {
        ok: false,
        message:
          'WordPress did not return a JWT. Install "JWT Authentication for WP REST API" on WordPress and configure it (see plugin docs / CORS if needed).',
        status: 502,
      };
    }
    return { ok: true, token };
  } catch (e) {
    return {
      ok: false,
      message: e instanceof Error ? e.message : "Network error",
      status: 502,
    };
  }
}

export type WpUserMe = {
  id: number;
  name: string;
  email: string;
  slug: string;
};

export async function fetchWpUserMe(
  jwt: string
): Promise<{ ok: true; user: WpUserMe } | { ok: false }> {
  const base = getWordPressUrl();
  if (!base) return { ok: false };
  try {
    const res = await fetch(`${base}/wp-json/wp/v2/users/me`, {
      headers: {
        Authorization: `Bearer ${jwt}`,
        Accept: "application/json",
      },
      cache: "no-store",
    });
    if (!res.ok) return { ok: false };
    const data = (await res.json()) as Record<string, unknown>;
    const id = typeof data.id === "number" ? data.id : Number(data.id);
    if (!Number.isFinite(id) || id <= 0) return { ok: false };
    const email = typeof data.email === "string" ? data.email : "";
    const name = typeof data.name === "string" ? data.name : "";
    const slug = typeof data.slug === "string" ? data.slug : "";
    return {
      ok: true,
      user: { id, name, email, slug },
    };
  } catch {
    return { ok: false };
  }
}
